import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    void testIsLineBreak_withNullCharacter() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        Boolean result = (Boolean) isLineBreakMethod.invoke(null, (Object) null);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_withLineBreakCharacters() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        Character[] lineBreakChars = {'\r', '\n'};
        for (Character c : lineBreakChars) {
            Boolean result = (Boolean) isLineBreakMethod.invoke(null, c);
            assertTrue(result, "Expected true for line break char: " + (int) c.charValue());
        }
    }

    @Test
    void testIsLineBreak_withNonLineBreakCharacter() throws Exception {
        Method isLineBreakMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", Character.class);
        isLineBreakMethod.setAccessible(true);

        Character nonLineBreakChar = 'a';
        Boolean result = (Boolean) isLineBreakMethod.invoke(null, nonLineBreakChar);
        assertFalse(result);
    }

    @Test
    void testIsLineBreak_privateIsLineBreakChar_method() throws Exception {
        Method isLineBreakCharMethod = CSVFormat.class.getDeclaredMethod("isLineBreak", char.class);
        isLineBreakCharMethod.setAccessible(true);

        // Test line break chars
        assertTrue((Boolean) isLineBreakCharMethod.invoke(null, '\r'));
        assertTrue((Boolean) isLineBreakCharMethod.invoke(null, '\n'));

        // Test non line break char
        assertFalse((Boolean) isLineBreakCharMethod.invoke(null, 'x'));
        assertFalse((Boolean) isLineBreakCharMethod.invoke(null, ' '));
    }
}
